#!/bin/bash
ssh root@192.168.200.38 "echo '=== VRAM ===' && nvidia-smi --query-gpu=name,memory.used,memory.total,memory.free --format=csv,noheader && echo '' && echo '=== DOCKER STATS ===' && docker stats --no-stream --format 'table {{.Name}}\t{{.MemUsage}}\t{{.MemPerc}}' && echo '' && echo '=== RECENT LOGS (tail 30) ===' && docker logs --tail=30 llama-llama-server-1 && echo '' && echo '=== MTP / SPEC LOGS ===' && docker logs llama-llama-server-1 2>&1 | grep -i 'spec\|draft\|mtp\|accept' | tail -10 && echo '' && echo '=== ERROR LOGS ===' && docker logs llama-llama-server-1 2>&1 | grep -i 'error\|warn\|fail\|oom\|out of memory' | head -10"
